+        };
+        ctrl.start_tracking("op1", 1, "a", &opts);
+
+        // First update emits
+        let first = ctrl.record_update("op1", make_update("a", 10, Some(100)), fixed_now());
+        assert!(first);
+
+        // Phase transition always emits
+        ctrl.record_phase_transition("op1", "b", &[], fixed_now());
